            v: t.MutableSequenceOf[str],
        ) -> t.MutableSequenceOf[str]:
            """Remove duplicate filters while preserving order."""
            seen: set[str] = set()
            result: t.MutableSequenceOf[str] = []
            for item in v:
                if item not in seen:
                    seen.add(item)
                    result.append(item)
            return result

