                    **self._EMPTY_VALIDATION_RESULT_PAYLOAD,
                    "rfc_violations": list(violations),
                    "errors": list[str](),
                    "warnings": list[str](),
                    "server_specific_violations": list[str](),
                    "context": context_payload,
